import java.util.ArrayList;
import java.util.List;

public List<String> cellRange(String s) {
    int r1 = s.charAt(1) - '0';
    int r2 = s.charAt(4) - '0';
    int c1 = s.charAt(0) - 'A' + 1;
    int c2 = s.charAt(3) - 'A' + 1;

    List<String> res = new ArrayList<>();
    for (int c = c1; c <= c2; ++c) {
        for (int r = r1; r <= r2; ++r) {
            res.add((char)('A' + c - 1) + Integer.toString(r));
        }
    }
    return res;
}
```

